2	 * Status Server — lightweight HTTP API + Mini App for /status monitoring.
3	 * Independent server on STATUS_PORT (default 3847).
4	 */
5	import { createServer, type Server, type IncomingMessage, type ServerResponse } from "node:http";
6	import { readFile, readdir, stat } from "node:fs/promises";
7	import path from "node:path";
8	import { listTasks, listActiveTasks, getTask, cancelTask } from "./status-store.js";
9	import { getSpecialists, type SpecialistEntry } from "./specialist.js";
10	import { getRecentEvents, type StateEvent } from "./event-log.js";
11	import { config } from "./config.js";
