13	let httpServer: Server | undefined;
14	
15	// SSE clients per taskId
16	const sseClients = new Map<string, Set<ServerResponse>>();
17	
18	// ─── Specialist helpers ────────────────────────────────────────────────────
19	
20	/** decodeURIComponent 對無效 percent-encoding（%zz）會 throw URIError，統一轉成 null 讓路由回 400。 */
21	function safeDecode(s: string): string | null {
22	  try { return decodeURIComponent(s); } catch { return null; }
23	}
24	
25	function escapeRegex(s: string): string {
26	  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
27	}
28	
29	/** env 可能含 API key 等機密，回傳前把機密欄位遮罩。 */
30	function maskEnv(env?: Record<string, string>): Record<string, string> | undefined {
31	  if (!env) return env;
32	  return Object.fromEntries(Object.entries(env).map(([k, v]) =>
33	    [k, /key|token|secret|password|credential/i.test(k) ? "••••••" : v]));
34	}
35	
36	function extractModel(entry: SpecialistEntry): string {
37	  const args = entry.harness.args;
38	  const idx = args.indexOf("--model");
39	  return idx >= 0 && idx + 1 < args.length ? args[idx + 1] : "default";
40	}
