322	// ─── SSE broadcast ─────────────────────────────────────────────────────────
323	
324	/** Broadcast an SSE event to all clients watching a task. */
325	export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
326	  const clients = sseClients.get(taskId);
327	  if (!clients || clients.size === 0) return;
328	  const payload = `data: ${JSON.stringify(data)}\n\n`;
329	  for (const res of clients) {
330	    res.write(payload);
331	  }
332	}
