113	        clients.add(ws);
114	        ws.on("close", () => clients.delete(ws));
115	        ws.on("error", () => clients.delete(ws));
116	        ws.on("message", (raw: any) => {
117	          try {
118	            const msg = JSON.parse(raw.toString());
119	            if (msg.type === "chat" && typeof msg.text === "string" && chatHandler) {
120	              chatHandler(msg.text);
