127	      return `❌ WS server 啟動失敗: ${e.message}`;
128	    }
129	  }
130	  const electron = path.join(process.cwd(), "node_modules", ".bin", "electron.cmd");
131	  console.log(`[pet] spawning: ${electron} in ${PET_DIR}`);
132	  petProc = spawn(electron, ["."], { cwd: PET_DIR, stdio: ["ignore", "pipe", "pipe"], detached: false, shell: true });
133	  petProc.stderr?.on("data", (d: Buffer) => console.error(`[pet:err] ${d.toString().trim()}`));
134	  petProc.on("exit", (code) => { console.log(`[pet] exited code=${code}`); petProc = null; });
135	  petProc.on("error", (e) => console.error(`[pet] spawn error: ${e.message}`));
136	  return "✅ Pet 已啟動";
