188	/**
189	 * Run a child process and collect stdout/stderr.
190	 * Resolves with {code, stdout, stderr} — never rejects on non-zero exit.
191	 */
192	function run(
193	  cmd: string,
194	  args: string[],
195	  cwd: string,
196	): Promise<{ code: number; stdout: string; stderr: string }> {
197	  return new Promise((resolve, reject) => {
198	    const proc = spawn(cmd, args, { cwd, shell: false });
199	    let stdout = "";
200	    let stderr = "";
201	    proc.stdout.on("data", (d) => (stdout += d.toString()));
202	    proc.stderr.on("data", (d) => (stderr += d.toString()));
203	    proc.on("error", reject);
204	    proc.on("close", (code) => {
205	      resolve({ code: code ?? -1, stdout, stderr });
206	    });
207	  });
208	}
