108	export async function analyzeForSpecialist(name: string): Promise<AnalysisResult> {
109	  const cfg = await loadDomainsConfig();
110	  const domain = cfg.domains[name];
111	  if (!domain) {
112	    throw new Error(
113	      `Unknown specialist domain "${name}". Known: ${Object.keys(cfg.domains).join(", ")}`,
114	    );
115	  }
116	
117	  // 1. Read skill-usage.json (centralized in MEMORY_DIR/config/)
118	  const skillDir = detectSkillDir();
119	  const usagePath = usageFilePath();
120	  const usage = await readJsonOrDefault<UsageJson>(usagePath, () => ({
121	    _schema_version: 1,
122	    _last_updated_at: null,
123	    skills: {},
124	  }));
125	
126	  // 2. Match skills by prefix (or all if inheritsAll)
127	  const matchedSkills: string[] = [];
128	  if (domain.inheritsAll) {
129	    matchedSkills.push(...Object.keys(usage.skills));
130	  } else {
131	    for (const skillName of Object.keys(usage.skills)) {
132	      if (domain.prefixes.some((p) => skillName.startsWith(p))) {
133	        matchedSkills.push(skillName);
134	      }
135	    }
136	  }
137	
138	  // 3. Read topics.json for secondary signal
139	  const topicsPath = path.join(config.memoryDir, "topics.json");
140	  let topics: TopicEntry[] = [];
141	  try {
142	    const raw = await readFile(topicsPath, "utf8");
143	    const jsonStr = raw.replace(/^\s*\/\/.*$/gm, "");
144	    topics = JSON.parse(jsonStr);
145	  } catch { /* ignore */ }
146	
147	  // 4. Find relevant topics by keyword overlap
148	  const relevantTopics: string[] = [];
149	  for (const t of topics) {
150	    const hasOverlap = t.keywords.some((kw) =>
151	      domain.topicKeywords.some((dk) => kw.includes(dk) || dk.includes(kw)),
152	    );
153	    if (hasOverlap) relevantTopics.push(t.topic);
154	  }
155	
156	  // 5. Resolve MCP servers from main.json
157	  const agentConfigDir = detectAgentConfigDir();
158	  const mainAgentPath = path.join(agentConfigDir, "agents", "main.json");
159	  let mainAgent: any = {};
160	  try {
161	    mainAgent = JSON.parse(await readFile(mainAgentPath, "utf8"));
162	  } catch { /* ignore */ }
163	
164	  const mcpServers: Record<string, any> = {};
165	  if (domain.inheritsAll) {
166	    // Inherit all MCP servers from main agent
167	    for (const [serverName, serverCfg] of Object.entries(mainAgent.mcpServers ?? {})) {
168	      mcpServers[serverName] = serverCfg;
169	    }
170	  } else {
171	    const allMcpNames = [...new Set([...(cfg.commonMcpServers ?? []), ...domain.mcpServers])];
172	    for (const serverName of allMcpNames) {
173	      if (mainAgent.mcpServers?.[serverName]) {
174	        mcpServers[serverName] = mainAgent.mcpServers[serverName];
175	      }
176	    }
177	  }
178	
179	  return {
180	    name,
181	    skills: matchedSkills.sort(),
182	    mcpServers,
183	    description: domain.description,
184	    relevantTopics,
185	  };
186	}
