197	/**
198	 * Build the CLI harness for a specialist from its domain config.
199	 *
200	 * `harness` is the full command string used as-is (split on whitespace).
201	 * Supports `{name}` placeholder for the specialist name.
202	 * Default: "kiro-cli acp --agent {name} -a"
203	 *
204	 * Examples:
205	 *   "kiro-cli acp --agent {name} -a"       → Kiro CLI
206	 *   "codex-acp --profile {name}"           → Codex (cola-io Rust binary)
207	 *   "npx @agentclientprotocol/claude-agent-acp" → Claude Agent SDK
208	 */
209	function buildHarness(name: string): { command: string; args: string[] } {
210	  const cfg = cached; // already loaded by caller
211	  const domain = cfg?.domains[name];
212	  const raw = (domain?.harness ?? cfg?.defaultHarness ?? "kiro-cli acp --agent {name} -a")
213	    .replace(/\{name\}/g, name);
214	  const parts = raw.trim().split(/\s+/);
215	  // Model via CLI flag only works for kiro-cli. claude-agent-acp silently
216	  // ignores --model/--effort in ACP mode — those pin via SpecialistEntry
217	  // model/effort → session/set_config_option instead (see resolveModelPin).
218	  const model = domain?.model ?? cfg?.defaultModel;
219	  if (model && parts[0].includes("kiro") && !parts.includes("--model")) {
220	    parts.push("--model", model);
221	  }
222	  return { command: parts[0], args: parts.slice(1) };
223	}
224	
225	/**
226	 * Resolve the ACP-level model/effort pin for a specialist entry. Only the
227	 * Claude adapter supports session/set_config_option, so return undefined
228	 * for other harnesses (Kiro takes --model in args, Codex takes -c model=).
229	 */
230	function resolveModelPin(name: string, harnessCommand: string): { model?: string; effort?: string } {
231	  if (!harnessCommand.includes("claude-agent-acp")) return {};
232	  const cfg = cached;
233	  const domain = cfg?.domains[name];
234	  return {
235	    model: domain?.model ?? cfg?.defaultModel,
236	    effort: domain?.effort ?? cfg?.defaultEffort,
237	  };
238	}
