240	/**
241	 * Resolve harness + model/effort pin for a domain WITHOUT materializing a
242	 * specialists.json entry. Used by MoA (src/moa.ts) to spawn ephemeral
243	 * reference advisors straight from specialist-domains.json.
244	 * Returns null when the domain is not defined.
245	 */
246	export async function resolveDomainSpawnSpec(
247	  name: string,
248	): Promise<{ harness: { command: string; args: string[] }; model?: string; effort?: string } | null> {
249	  const cfg = await loadDomainsConfig();
250	  if (!cfg.domains[name]) return null;
251	  const harness = buildHarness(name);
252	  // Match against the FULL command line: with "npx @agentclientprotocol/
253	  // claude-agent-acp" the adapter name lives in args, not command — matching
254	  // command alone silently drops the model/effort pin.
255	  const pin = resolveModelPin(name, [harness.command, ...harness.args].join(" "));
256	  return { harness, ...pin };
257	}
