319	  await mkdir(cwdResolved, { recursive: true });
320	
321	  return {
322	    agentConfigPath,
323	    specialistsJsonPath: specialistsPath,
324	    skills: analysis.skills,
325	    mcpServers: Object.keys(analysis.mcpServers),
326	  };
327	}
