329	async function buildResourceGlobs(skills: string[], domainPrefixes?: string[], skipCommonSkills?: boolean): Promise<string[]> {
330	  const cfg = await loadDomainsConfig();
331	  const skillDir = detectSkillDir().replace(/\\/g, "/");
332	
333	  // Empty prefixes = full-capability agent, give all skills
334	  if (!domainPrefixes || domainPrefixes.length === 0) {
335	    return [`skill://${skillDir}/**/SKILL.md`];
336	  }
337	
338	  // Domain-specific globs from prefix groups
339	  const prefixGroups = new Map<string, string[]>();
340	  for (const s of skills) {
341	    const match = s.match(/^((?:ms-|uk-)?[a-z]+)-/);
342	    const prefix = match ? match[0] : s + "-";
343	    if (!prefixGroups.has(prefix)) prefixGroups.set(prefix, []);
344	    prefixGroups.get(prefix)!.push(s);
345	  }
346	
347	  const globs: string[] = [];
348	  for (const [prefix] of prefixGroups) {
349	    globs.push(`skill://${skillDir}/${prefix}*/SKILL.md`);
350	  }
351	
352	  // Common skills (unless domain opts out)
353	  if (!skipCommonSkills) {
354	    for (const s of cfg.commonSkills) {
355	      globs.push(`skill://${skillDir}/${s}/SKILL.md`);
356	    }
357	  }
358	
359	  return [...new Set(globs)];
360	}
