521	export async function buildSpecialistPreamble(
522	  name: string,
523	  userId: number,
524	  opts?: { proxy?: boolean },
525	): Promise<string> {
526	  const cfg = await loadDomainsConfig();
527	  const domain = cfg.domains[name];
528	  if (!domain) return "";
529	
530	  // Read static preamble file if configured (or fall back to conventional path)
531	  let staticPreamble = "";
532	  const preambleSrc = domain.preambleFile ?? `\${BRIDGE_DIR}/specialists/${name}/preamble.md`;
533	  const resolved = preambleSrc
534	    .replace(/\$\{BRIDGE_DIR\}/g, path.resolve(config.sessionCwd))
535	    .replace(/\$\{MEMORY_DIR\}/g, config.memoryDir);
536	  try {
537	    staticPreamble = await readFile(resolved, "utf8");
538	  } catch { /* file missing, skip */ }
539	
540	  // Read shared user-preferences and git-context
541	  const sharedDir = path.join(config.sessionCwd, "specialists", "shared");
542	  const sharedFiles = ["policies.md", "user-preferences.md", "git-context.md"];
543	  if (opts?.proxy) sharedFiles.unshift("bridge-tools.md");
544	  for (const f of sharedFiles) {
545	    try {
546	      staticPreamble += "\n" + await readFile(path.join(sharedDir, f), "utf8");
547	    } catch { /* skip if missing */ }
548	  }
549	
550	  // Read topics.json to find relevant topic names
551	  const topicsPath = path.join(config.memoryDir, "topics.json");
552	  let topics: TopicEntry[] = [];
553	  try {
554	    const raw = await readFile(topicsPath, "utf8");
555	    const jsonStr = raw.replace(/^\s*\/\/.*$/gm, "");
556	    topics = JSON.parse(jsonStr);
557	  } catch { /* ignore */ }
558	
559	  const relevantTopics: string[] = [];
560	  if (domain.inheritsAll) {
561	    for (const t of topics) relevantTopics.push(t.topic);
562	  } else {
563	    for (const t of topics) {
564	      const hasOverlap = t.keywords.some((kw) =>
565	        domain.topicKeywords.some((dk) => kw.includes(dk) || dk.includes(kw)),
566	      );
567	      if (hasOverlap) relevantTopics.push(t.topic);
568	    }
569	  }
570	
571	  // Read facts from relevant topic shards
572	  const shardDir = path.join(config.memoryDir, `facts_Topic`, String(userId));
573	  const facts: string[] = [];
574	  for (const topic of relevantTopics) {
575	    try {
576	      const shardPath = path.join(shardDir, `${topic}.md`);
577	      const content = await readFile(shardPath, "utf8");
578	      const lines = content.split(/\r?\n/).filter((l) => l.trim().startsWith("- "));
579	      facts.push(...lines);
580	    } catch { /* shard doesn't exist, skip */ }
581	  }
582	
583	  if (facts.length === 0) return staticPreamble ? staticPreamble + "\n\n" : "";
584	
585	  const recent = facts.slice(-50);
586	
587	  let result = (staticPreamble ? staticPreamble + "\n\n" : "");
588	
589	  // Add notebook scope hint if domain has notebooks configured (skip for inheritsAll)
590	  if (!domain.inheritsAll && (domain.wikiPages?.length || domain.notebooks?.length)) {
591	    const lines: string[] = ["[Knowledge scope for this specialist]"];
592	    if (domain.notebooks?.length) {
593	      lines.push(`Allowed NotebookLM notebooks: ${domain.notebooks.join(", ")}`);
594	      lines.push("Do not query notebooks outside this list.");
595	    }
596	    if (domain.wikiPages?.length) {
597	      lines.push(`Relevant wiki pages: ${domain.wikiPages.join(", ")}`);
598	    }
599	    lines.push("[End knowledge scope]\n");
600	    result += lines.join("\n") + "\n";
601	  }
602	
603	  result +=
604	    `[Specialist context — relevant facts for "${name}" domain]\n` +
605	    recent.join("\n") +
606	    `\n[End specialist context]\n\n`;
607	
608	  // Phase B+: inject persistent memory (lessons from previous delegations)
609	  const memory = await readMemory(name);
610	  if (memory) {
611	    result +=
612	      `[Persistent memory — lessons from your previous tasks]\n` +
613	      memory +
614	      `\n[End persistent memory]\n\n`;
615	  }
616	
617	  // Artifact output instruction
618	  result +=
619	    `[Artifact output]\n` +
620	    `任務完成後，在回覆最末附一個 JSON block 供系統存檔：\n` +
621	    "```json\n" +
622	    `{"type":"artifact","summary":"一句話摘要","outputs":[{"type":"finding","content":"..."}],"files_modified":[],"tags":["tag1"]}\n` +
623	    "```\n" +
624	    `outputs.type 可用：finding, code_change, recommendation, analysis。\n` +
625	    `tags 用英文小寫。如果任務失敗或無有意義產出，不需要附。\n` +
626	    `[End artifact output]\n\n`;
627	
628	  return result;
629	}
