634	import type { EnrichmentScope } from "./enrichment.js";
635	import { getTopicRules } from "./topic-rules.js";
636	
637	/**
638	 * Build an EnrichmentScope for a specialist domain, resolving topicKeywords
639	 * into actual topic names from topics.json.
640	 */
641	export async function getSpecialistScope(name: string): Promise<EnrichmentScope | undefined> {
642	  const cfg = await loadDomainsConfig();
643	  const domain = cfg.domains[name];
644	  if (!domain) return undefined;
645	
646	  // Resolve topicKeywords → actual topic names
647	  if (domain.inheritsAll) {
648	    return { wikiPages: undefined, notebooks: undefined, topics: undefined };
649	  }
650	  const rules = getTopicRules();
651	  const topics: string[] = [];
652	  for (const rule of rules) {
653	    const hasOverlap = rule.keywords.some((kw) =>
654	      domain.topicKeywords.some((dk) => kw.includes(dk) || dk.includes(kw)),
655	    );
656	    if (hasOverlap) topics.push(rule.topic);
657	  }
658	
659	  return {
660	    wikiPages: domain.wikiPages?.length ? domain.wikiPages : undefined,
661	    notebooks: domain.notebooks?.length ? domain.notebooks : undefined,
662	    topics: topics.length ? topics : undefined,
663	  };
664	}
